import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { readTranscriptDelta } from "./transcriptReader.js";
function writeFixture(records) {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-transcript-"));
    const file = path.join(dir, "transcript.jsonl");
    fs.writeFileSync(file, `${records.map((row) => JSON.stringify(row)).join("\n")}\n`);
    return file;
}
describe("readTranscriptDelta", () => {
    let dir;
    beforeEach(() => {
        dir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-transcript-"));
    });
    afterEach(() => {
        fs.rmSync(dir, { recursive: true, force: true });
    });
    it("returns empty for an empty range", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: { role: "user", content: "hi" },
            },
        ]);
        const stat = fs.statSync(file);
        const result = readTranscriptDelta(file, stat.size);
        expect(result.turns).toEqual([]);
        expect(result.newOffset).toBe(stat.size);
    });
    it("normalises a user → assistant exchange", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: { role: "user", content: "hello" },
            },
            {
                timestamp: "2026-05-04T00:00:01Z",
                message: {
                    role: "assistant",
                    content: [{ type: "text", text: "hi back" }],
                    usage: { input_tokens: 5, output_tokens: 3 },
                },
            },
        ]);
        const result = readTranscriptDelta(file, 0);
        expect(result.turns).toHaveLength(2);
        expect(result.turns[0]).toMatchObject({
            sequence: 0,
            role: "user",
            content: "hello",
        });
        expect(result.turns[1]).toMatchObject({
            sequence: 1,
            role: "assistant",
            usage: { input_tokens: 5, output_tokens: 3 },
        });
        expect(result.malformedLines).toBe(0);
    });
    it("extracts assistant tool_use blocks into toolCalls", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: {
                    role: "assistant",
                    content: [
                        { type: "text", text: "running tool" },
                        { type: "tool_use", name: "Read", input: { file_path: "/x" } },
                    ],
                },
            },
        ]);
        const result = readTranscriptDelta(file, 0);
        expect(result.turns[0].toolCalls).toEqual([
            { type: "tool_use", name: "Read", input: { file_path: "/x" } },
        ]);
    });
    it("relabels user-role tool_result envelopes as tool_result turns", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: {
                    role: "user",
                    content: [{ type: "tool_result", text: "ok" }],
                },
            },
        ]);
        const result = readTranscriptDelta(file, 0);
        expect(result.turns[0].role).toBe("tool_result");
    });
    it("counts malformed lines without throwing", () => {
        const file = path.join(dir, "transcript.jsonl");
        fs.writeFileSync(file, `${[
            JSON.stringify({
                timestamp: "2026-05-04T00:00:00Z",
                message: { role: "user", content: "ok" },
            }),
            "not json at all",
            JSON.stringify({ message: {} }),
            JSON.stringify({
                timestamp: "2026-05-04T00:00:02Z",
                message: { role: "assistant", content: "hi" },
            }),
        ].join("\n")}\n`);
        const result = readTranscriptDelta(file, 0);
        expect(result.malformedLines).toBe(2);
        expect(result.turns).toHaveLength(2);
        expect(result.turns[0].sequence).toBe(0);
        expect(result.turns[1].sequence).toBe(3);
    });
    it("handles partial trailing line by holding the byte offset back", () => {
        const file = path.join(dir, "transcript.jsonl");
        const completeLine = JSON.stringify({
            timestamp: "2026-05-04T00:00:00Z",
            message: { role: "user", content: "complete" },
        });
        const partial = '{"timestamp":"2026-05-04T00:00:01Z","message":{"role":"user","content":"par';
        fs.writeFileSync(file, `${completeLine}\n${partial}`);
        const result = readTranscriptDelta(file, 0);
        expect(result.turns).toHaveLength(1);
        const stat = fs.statSync(file);
        expect(result.newOffset).toBeLessThan(stat.size);
        expect(result.newOffset).toBe(completeLine.length + 1);
    });
    it("returns no turns when file shrank below offset (compaction signal)", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: { role: "user", content: "hi" },
            },
        ]);
        const stat = fs.statSync(file);
        const result = readTranscriptDelta(file, stat.size + 100);
        expect(result.turns).toEqual([]);
        expect(result.newOffset).toBe(stat.size);
    });
    it("preserves sequence numbers across partial reads", () => {
        const file = writeFixture([
            {
                timestamp: "2026-05-04T00:00:00Z",
                message: { role: "user", content: "a" },
            },
            {
                timestamp: "2026-05-04T00:00:01Z",
                message: { role: "assistant", content: "b" },
            },
        ]);
        const first = readTranscriptDelta(file, 0);
        expect(first.turns.map((turn) => turn.sequence)).toEqual([0, 1]);
        fs.appendFileSync(file, `${JSON.stringify({
            timestamp: "2026-05-04T00:00:02Z",
            message: { role: "user", content: "c" },
        })}\n`);
        const second = readTranscriptDelta(file, first.newOffset);
        expect(second.turns).toHaveLength(1);
        expect(second.turns[0].sequence).toBe(2);
    });
});
